    Args:
        search_results: List of SearchResult objects to aggregate
        group_by_field: Metadata field name to group by
        aggregation_funcs: Optional dictionary mapping statistic_name to aggregation
            function. Each function will be called with the list of SearchResult
            objects belonging to a group and should return a single aggregated value.

            Example:
                {
                    "count": lambda group: len(group),
                    "max_score": lambda group: max(r.score for r in group),
                    "min_score": lambda group: min(r.score for r in group),
                }

            If None, defaults to:
                - "count": number of results in the group
                - "avg_score": average of SearchResult.score for the group
                - "max_score": maximum SearchResult.score for the group
                - "min_score": minimum SearchResult.score for the group

    Returns:
        Dictionary mapping group_value to aggregated statistics.

        Example:
            {
                "tech": {
                    "count": 5,
                    "avg_score": 0.85,
                    "max_score": 0.95,
                    "min_score": 0.70,
                },
                "unknown": {
                    "count": 2,
                    "avg_score": 0.60,
                    "max_score": 0.65,
                    "min_score": 0.55,
                },
            }
    """
    # Group results by the requested field; use "unknown" if the field is missing
    grouped_results: Dict[str, List[SearchResult]] = defaultdict(list)
    for result in search_results:
        # Try attribute first, then metadata dict
        group_value = getattr(result, group_by_field, None)
        if group_value is None:
            metadata = getattr(result, "metadata", {}) or {}
            group_value = metadata.get(group_by_field)

        if group_value is None:
            group_key = "unknown"
        else:
            group_key = str(group_value)

        grouped_results[group_key].append(result)

    # If no custom aggregation functions are provided, use sensible defaults
    if aggregation_funcs is None:
        def _default_aggregations(group: List[SearchResult]) -> Dict[str, Any]:
            if not group:
                return {
                    "count": 0,
                    "avg_score": 0.0,
                    "max_score": None,
                    "min_score": None,
                }
            scores = [float(r.score) for r in group if getattr(r, "score", None) is not None]
            if not scores:
                return {
                    "count": len(group),
                    "avg_score": 0.0,
                    "max_score": None,
                    "min_score": None,
                }
            return {
                "count": len(group),
                "avg_score": sum(scores) / len(scores),
                "max_score": max(scores),
                "min_score": min(scores),
            }

        aggregated: Dict[str, Dict[str, Any]] = {}
        for group_key, group in grouped_results.items():
            aggregated[group_key] = _default_aggregations(group)
        return aggregated

    # When custom aggregation functions are provided, call each with the group
    aggregated: Dict[str, Dict[str, Any]] = {}
    for group_key, group in grouped_results.items():
